+fn make_proposal(
+    id: &str,
+    kind: ExperimentKind,
+    signal: AcquisitionSignal,
+    strength: u64,
+    gain: u64,
+    cost: u64,
+) -> ExperimentProposal {
+    ExperimentProposal::new(
+        id.to_string(),
+        kind,
+        format!("cell-{id}"),
+        vec![(signal, strength)],
+        gain,
+        300_000,
+        cost,
+        format!("test proposal {id}"),
+    )
+}
+
+fn default_weights() -> BTreeMap<String, u64> {
+    BTreeMap::new()
+}
